// SNC buffer setup
const SNC_BUFFER_SIZE = 500;
const sncBuffers = [[], [], []];

function handleSnc(data) {
  const [ch1, ch2, ch3] = data.values;
  // Extend buffers with ALL samples (not just latest)
  sncBuffers[0].push(...ch1);
  sncBuffers[1].push(...ch2);
  sncBuffers[2].push(...ch3);
  // Trim to buffer size
  sncBuffers.forEach(buf => {
    if (buf.length > SNC_BUFFER_SIZE) buf.splice(0, buf.length - SNC_BUFFER_SIZE);
  });
  // Latest reading per channel for HUD display
  const latest = sncBuffers.map(buf => buf[buf.length - 1]);
}

