javascript.code:
const ws = new WebSocket('ws://127.0.0.1:8766');

ws.onopen = () => {
  ws.send(JSON.stringify({command: 'subscribe', signal: 'gesture'}));
  ws.send(JSON.stringify({command: 'subscribe', signal: 'pressure'}));
  ws.send(JSON.stringify({command: 'subscribe', signal: 'snc'}));
};

ws.onmessage = (event) => {
  const msg = JSON.parse(event.data);
  switch (msg.type) {
    case 'gesture':
      console.log(`Gesture: ${msg.data.type}`);
      break;
    case 'pressure':
      console.log(`Pressure: ${msg.data.normalized * 100}%`);
      break;
    case 'navigation':
      console.log(`Movement: X=${msg.data.delta_x}, Y=${msg.data.delta_y}`);
      break;
    case 'snc':
      // values = [[ch1_samples], [ch2_samples], [ch3_samples]]
      const [ch1, ch2, ch3] = msg.data.values;
      console.log(`SNC latest: ch1=${ch1[ch1.length-1]} ch2=${ch2[ch2.length-1]} ch3=${ch3[ch3.length-1]}`);
      break;
  }
};

